def remove_Occ(s: str, char: str) -> str:
    if not s or not char:
        return s

    start = s.find(char)
    end = s.rfind(char)

    if start == -1 or end == -1:
        return s

    if start == end:
        # Only one occurrence
        return s[:start] + s[start+1:]
    elif start == 0 and end == len(s) - 1:
        # First and last characters
        return s[1:-1]
    else:
        # Remove from start to end
        return s[:start] + s[end+1:]

